      "n": 1,
      "column": "left",
      "text": "Un kahdá Deená fazzija\nJonatans Saula Dehls\nus fatwu Puifi/ kas win-\nna Bruzzas nette: Nahz/ eima\npahri us to Wilisteru Lehgeri/ kas\nwinna Puiffé irr/ un winch to\nfawain Tehwain ne pasazzija."
    },
    {
      "n": 2,
      "column": "left",
      "text": "Un Sauls palifke eefsch Gi-\nbejas Rohbeschahm appakfch ta\nGranata Rohka/kas Migroná bi-\nja/ un to Zauschu/ kas pee win-\nna bija/ pee fetchjunts Wihreem."
    },
    {
      "n": 3,
      "column": "left",
      "text": "Un Akijus/ tas Dehls Akita-\nba/ ta Brahta Jkabada/ ta Deh-\nla Pineafa/ ta Dehla Eelus/ bija\nta KUNGA Preesteris eefsch\nSihlus/nesdants to Eewodu/ bet\ntee Laudis ne sinnaja/ ka Jona-\ntans btj nogahjis."
    },
    {
      "n": 4,
      "column": "left",
      "text": "Bet tur bija starp tahin\npahretjamnahm Weetahm/ zaur ko\nJonatans mekleja pahreet us to\nWilisteru Lehgeri/ divi aft Ak-\nmika-Ralnt/ weens fchai Puiffé/\nohtrs winná Puiffé / un wee-\nnam bija tas Wahrdé Bozej/\nun ohtraim bija tas Wahrdé\nSenne."
    },
    {
      "n": 5,
      "column": "left",
      "text": "Ta weena Gals steeplahs\nprett Seemeta puffi prett Mik-\nmasu/ unta ohtra prett Deenas.\nWiddu Gebai pretti."
    },
    {
      "n": 6,
      "column": "left",
      "text": "Un Jonatans fazzija us to"
    },
    {
      "n": 7,
      "column": "right",
      "text": "Tad fazzija winna Bruz-\nan-Nettejs us to: Darrí wiha\nkas tawá Sirdí irr/ greesees\nreds/ es etmu ar tew/ pehz wiha\ntawas Sirds Prahtu."
    },
    {
      "n": 8,
      "column": "right",
      "text": "Tad fazzija Jonatans\nRaugi / mehs eefim pahri pe-\nteem Wihreemi/ un parahdifimee\nwinneem."
    },
    {
      "n": 9,
      "column": "right",
      "text": "Ja tee ta us mums fazzihis\npastahweet/ teekams mehs pe-\njums tikfim/ tad gribbam meh-\nfawá Weetá pastahweht/ un u-\nnskahpfim pee winneem."
    },
    {
      "n": 10,
      "column": "right",
      "text": "Bet ja tee ta fazzihis\nUskahpeet pee mums/ tad gri-\nbam mehs uskahpt / jo tas-\nKUNGS irr tohs muhsu Rohk-\ndewis/ un tas buhs mums pa-\nweenu Sihmi."
    },
    {
      "n": 11,
      "column": "right",
      "text": "Rad nu tee abbee to Wil-\nsteru Lehgeram parahdifahs/ tad\nfazzija tee Wilisteri/ raugi / te-\nGebreeri irr no tahm Allahm is-\ngahjufchi / kur tee btj apflehpu-\nschees."
    },
    {
      "n": 12,
      "column": "right",
      "text": "Un ta Lehgera Wihri af-\nbildeja Jonatanam un winna-\nBruzzu-Nettejam / un fazzija\nNahzeet pee mumsaufcha/ mehe-\njums gribbam fo mahziht. Tad-\nfazzija Jonatans us fawn Bruz-\nan-Netteju/uskahp man pakkat/"
    }
  ],
